import{_ as a,c as i,o as d,a1 as e}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"プラットフォームと統合：macOS、Windows、Linux ターミナル機能とサポート詳細 | opencode-notify","description":"opencode-notify の macOS、Windows、Linux での機能の違いを学び、ターミナルサポート（37以上のターミナルエミュレーター）、フォーカス検出、クリックフォーカス、カスタムサウンドなどのプラットフォーム機能を習得します。この章ではプラットフォーム機能の比較、ターミナル検出メカニズム、設定ガイドを含み、オペレーティングシステムとターミナルタイプに応じて通知体験を最適化し、作業効率を向上させます。","frontmatter":{"title":"プラットフォームと統合：macOS、Windows、Linux ターミナル機能とサポート詳細 | opencode-notify","sidebarTitle":"あなたのプラットフォームに合わせる","subtitle":"プラットフォームと統合","description":"opencode-notify の macOS、Windows、Linux での機能の違いを学び、ターミナルサポート（37以上のターミナルエミュレーター）、フォーカス検出、クリックフォーカス、カスタムサウンドなどのプラットフォーム機能を習得します。この章ではプラットフォーム機能の比較、ターミナル検出メカニズム、設定ガイドを含み、オペレーティングシステムとターミナルタイプに応じて通知体験を最適化し、作業効率を向上させます。","tags":["プラットフォーム機能","ターミナルサポート","システム互換性"],"prerequisite":["start-quick-start","start-how-it-works"],"order":2},"headers":[],"relativePath":"ja/kdcokenny/opencode-notify/platforms/index.md","filePath":"ja/kdcokenny/opencode-notify/platforms/index.md"}'),o={name:"ja/kdcokenny/opencode-notify/platforms/index.md"};function l(r,t,n,s,h,c){return d(),i("div",null,[...t[0]||(t[0]=[e('<h1 id="プラットフォームと統合" tabindex="-1">プラットフォームと統合 <a class="header-anchor" href="#プラットフォームと統合" aria-label="Permalink to &quot;プラットフォームと統合&quot;">​</a></h1><p>本章节は、異なるオペレーティングシステムでの opencode-notify の機能の違いを理解し、プラットフォーム固有の設定を習得し、ターミナルのパフォーマンスを最適化する方法を学びます。</p><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><h3 id="_1-macos-プラットフォーム機能" tabindex="-1">1. <a href="./../macos/">macOS プラットフォーム機能</a> <a class="header-anchor" href="#_1-macos-プラットフォーム機能" aria-label="Permalink to &quot;1. [macOS プラットフォーム機能](../macos/)&quot;">​</a></h3><p>macOS 上の高度な機能について包括的に理解します。インテリジェントなフォーカス検出、クリック通知フォーカス、カスタムサウンドが含まれます。</p><ul><li>フォーカス検出：ターミナルが現在アクティブなウィンドウかどうかを自動的に判断</li><li>クリックフォーカス：通知をクリックした後に自動的にターミナルに切り替え</li><li>カスタムサウンド：異なるイベントに固有のサウンドを設定</li><li>37+ ターミナルサポート：Ghostty、iTerm2、VS Code 統合ターミナルなどが含まれます</li></ul><h3 id="_2-windows-プラットフォーム機能" tabindex="-1">2. <a href="./../windows/">Windows プラットフォーム機能</a> <a class="header-anchor" href="#_2-windows-プラットフォーム機能" aria-label="Permalink to &quot;2. [Windows プラットフォーム機能](../windows/)&quot;">​</a></h3><p>Windows プラットフォームでの通知の基礎と設定方法を習得します。</p><ul><li>ネイティブ通知：Windows 10/11 通知センターを使用</li><li>通知権限：OpenCode に通知を送信する権限があることを確認</li><li>基本設定：Windows 環境での設定ファイルの場所</li><li>制限事項：Windows ではフォーカス検出機能は現在サポートされていません</li></ul><h3 id="_3-linux-プラットフォーム機能" tabindex="-1">3. <a href="./../linux/">Linux プラットフォーム機能</a> <a class="header-anchor" href="#_3-linux-プラットフォーム機能" aria-label="Permalink to &quot;3. [Linux プラットフォーム機能](../linux/)&quot;">​</a></h3><p>Linux プラットフォームでの通知メカニズムと依存関係のインストールについて理解します。</p><ul><li>libnotify 統合：notify-send を使用して通知を送信</li><li>デスクトップ環境サポート：GNOME、KDE Plasma、XFCE などの主流環境</li><li>依存関係のインストール：異なるディストリビューションでのインストールコマンド</li><li>制限事項：Linux ではフォーカス検出機能は現在サポートされていません</li></ul><h3 id="_4-対応ターミナル" tabindex="-1">4. <a href="./../terminals/">対応ターミナル</a> <a class="header-anchor" href="#_4-対応ターミナル" aria-label="Permalink to &quot;4. [対応ターミナル](../terminals/)&quot;">​</a></h3><p>すべての 37 以上の対応ターミナルエミュレーターを確認し、自動検出メカニズムを理解します。</p><ul><li>ターミナル検出：ターミナルタイプを自動的に識別する方法</li><li>ターミナルリスト：対応ターミナルの完全なリスト</li><li>手動設定：自動検出が失敗した場合に手動で指定する方法</li><li>特殊なターミナル：VS Code 統合ターミナル、リモート SSH セッションの処理</li></ul><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">本章节を学習する前に、以下を完了してください</p><ul><li>✅ <strong><a href="./../../start/quick-start/">クイックスタート</a></strong>：opencode-notify のインストールが完了している</li><li>✅ <strong><a href="./../../start/how-it-works/">仕組み</a></strong>：4種類の通知タイプとインテリジェントなフィルタリングメカニズムを理解している</li></ul></div><h2 id="プラットフォーム選択の推奨事項" tabindex="-1">プラットフォーム選択の推奨事項 <a class="header-anchor" href="#プラットフォーム選択の推奨事項" aria-label="Permalink to &quot;プラットフォーム選択の推奨事項&quot;">​</a></h2><p>オペレーティングシステムに応じて、対応する章を選択してください：</p><table tabindex="0"><thead><tr><th>オペレーティングシステム</th><th>推奨学習順序</th><th>コア機能</th></tr></thead><tbody><tr><td><strong>macOS</strong></td><td>1. macOS プラットフォーム機能 → 4. 対応ターミナル</td><td>フォーカス検出、クリックフォーカス、カスタムサウンド</td></tr><tr><td><strong>Windows</strong></td><td>2. Windows プラットフォーム機能 → 4. 対応ターミナル</td><td>ネイティブ通知、基本設定</td></tr><tr><td><strong>Linux</strong></td><td>3. Linux プラットフォーム機能 → 4. 対応ターミナル</td><td>libnotify 統合、依存関係のインストール</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">一般的な推奨事項</p><p>どのプラットフォームを使用していても、第4課「対応ターミナル」は学習する価値があります。ターミナル検出メカニズムを理解し、設定問題を解決するのに役立ちます。</p></div><h2 id="機能比較表" tabindex="-1">機能比較表 <a class="header-anchor" href="#機能比較表" aria-label="Permalink to &quot;機能比較表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>機能</th><th>macOS</th><th>Windows</th><th>Linux</th></tr></thead><tbody><tr><td>ネイティブ通知</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>ターミナルフォーカス検出</td><td>✅</td><td>❌</td><td>❌</td></tr><tr><td>クリック通知フォーカス</td><td>✅</td><td>❌</td><td>❌</td></tr><tr><td>カスタムサウンド</td><td>✅</td><td>✅</td><td>✅ (一部)</td></tr><tr><td>ミュート時間帯</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>親セッションチェック</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>37+ ターミナルサポート</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>自動ターミナル検出</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>本章节を完了すると、異なるプラットフォームでの機能の違いと設定方法を理解できます。</p><p>引き続き以下を学習することをお勧めします：</p><h3 id="高度な設定" tabindex="-1"><a href="./../../advanced/config-reference/">高度な設定</a> <a class="header-anchor" href="#高度な設定" aria-label="Permalink to &quot;[高度な設定](../../advanced/config-reference/)&quot;">​</a></h3><p>設定ファイルのすべてのオプションについて深く学び、高度な設定のスキルを習得します。</p><ul><li>完全な設定リファレンス：すべての設定項目の詳細な説明</li><li>ミュート時間帯の詳細：設定方法と動作原理</li><li>ターミナル検出の原理：自動検出の内部メカニズム</li><li>高度な使用法：設定のヒントとベストプラクティス</li></ul><h3 id="トラブルシューティング" tabindex="-1"><a href="./../../faq/troubleshooting/">トラブルシューティング</a> <a class="header-anchor" href="#トラブルシューティング" aria-label="Permalink to &quot;[トラブルシューティング](../../faq/troubleshooting/)&quot;">​</a></h3><p>問題が発生した場合は、一般的な故障の解決策を確認してください。</p><ul><li>通知が表示されない：権限とシステム設定の問題</li><li>フォーカス検出が動作しない：ターミナル設定と検出メカニズム</li><li>設定エラー：設定ファイルの形式とフィールドの説明</li><li>サウンドの問題：サウンド設定とシステム互換性</li></ul><div class="info custom-block"><p class="custom-block-title">学習パスの推奨事項</p><p>初めて使用する場合は、<strong>プラットフォーム章 → 高度な設定 → トラブルシューティング</strong> の順序で学習することをお勧めします。特定の問題に遭遇した場合は、トラブルシューティングの章に直接ジャンプできます。</p></div>',33)])])}const f=a(o,[["render",l]]);export{p as __pageData,f as default};
